export function getZodiacBySlug(slug: string): ZodiacSignData | undefined {
  return ZODIAC_DATA.find(z => z.slug === slug);
}

export function getZodiacByDate(month: number, day: number): ZodiacSignData | undefined {
  return ZODIAC_DATA.find(z => {
    if (z.startMonth === z.endMonth) {
      return month === z.startMonth && day >= z.startDay && day <= z.endDay;
    }
    if (month === z.startMonth) return day >= z.startDay;
    if (month === z.endMonth) return day <= z.endDay;
    return false;
  });
}

